+            schema_version: EXPLAIN_SESSION_SCHEMA_VERSION.to_owned(),
+            generated_at_ms: pressure_timestamp_ms(),
+            query: query.to_owned(),
+            phase,
+            rrf_k,
+            hits,
+        }
+    }
